sub extract_text {
    my ($pdf_file) = @_;

    my $pdf = CAM::PDF->new($pdf_file);
    my $num_pages = $pdf->numPages();
    my @all_text;

    for (my $page = 1; $page <= $num_pages; $page++) {
        my $page_text = $pdf->getPageText($page);
        push @all_text, $page_text;
    }

    return join("\n", @all_text);
}

